type NavigateFunc = (to: string, options?: { replace?: boolean } | undefined) => void;

let _navigate: NavigateFunc | null = null;

export const setNavigate = (fn: NavigateFunc) => {
  _navigate = fn;
};

export const navigate = (to: string, options?: { replace?: boolean }) => {
  if (_navigate) {
    try {
      _navigate(to, options);
      return;
    } catch {
      // fallback to location change if react-router navigation fails
    }
  }

  if (options?.replace) {
    globalThis.location.replace(to);
  } else {
    globalThis.location.href = to;
  }
};

export const resetNavigate = () => {
  _navigate = null;
};

/**
 * notifications.ts — Singleton bridge to Ant Design's message/notification APIs.
 *
 * Ant Design v5 requires hook-based `App.useApp()` to display toasts inside the
 * theme context. This bridge captures those APIs once at mount (via
 * <NotificationBridge />) so non-React code (axios interceptors, utils) can
 * still trigger toasts.
 */

type MessageApi = {
  success: (content: string) => void;
  error: (content: string) => void;
  warning: (content: string) => void;
  info: (content: string) => void;
};

let messageApi: MessageApi | null = null;

export function registerMessageApi(api: MessageApi): void {
  messageApi = api;
}

export const notify = {
  success(content: string) {
    if (messageApi) messageApi.success(content);
  },
  error(content: string) {
    if (messageApi) messageApi.error(content);
  },
  warning(content: string) {
    if (messageApi) messageApi.warning(content);
  },
  info(content: string) {
    if (messageApi) messageApi.info(content);
  },
};

/**
 * httpClient.ts — Central axios client
 * - Factory `createApiClient(baseURL?)` that attaches:
 *   - withCredentials: true — sends HttpOnly cookies automatically
 *   - response interceptor: dispatches auth:loggedOut on 401 and redirects to login
 *
 * SECURITY: JWT is stored in HttpOnly cookie (not localStorage).
 * The browser sends the cookie automatically with `withCredentials: true`.
 */
import axios, { isAxiosError as axiosIsAxiosError } from "axios";
import { navigate } from "./navigation";
import { config } from "../../config/env";
import { notify } from "./notifications";

export function createApiClient(baseURL?: string) {
  const api = axios.create({
    baseURL,
    withCredentials: true, // Send HttpOnly cookies with every request
  });

  // Expose a small helper on the created instance so code that imports the
  // client as `axios` can still call `axios.isAxiosError(...)` safely.
  (api as unknown as Record<string, unknown>).isAxiosError = (error: unknown) => {
    try {
      return axiosIsAxiosError ? axiosIsAxiosError(error as Record<string, unknown>) : (error as Record<string, unknown>)?.isAxiosError === true;
    } catch {
      return (error as Record<string, unknown>)?.isAxiosError === true;
    }
  };

  // No request interceptor needed — HttpOnly cookie is sent automatically

  api.interceptors.response.use(
    (response) => response,
    (error) => {
      const status = error?.response?.status;
      const url = error?.config?.url;

      const urlStr = String(url || "");
      const isFormationApi =
        (config?.FORMATION_URL && urlStr.includes(config.FORMATION_URL)) || urlStr.includes("/formation/");

      if (status === 401) {
        if (isFormationApi) {
          return Promise.reject(error);
        }

        try {
          globalThis.dispatchEvent(new Event("auth:loggedOut"));
        } catch {
          /* ignore */
        }
        const isAlreadyOnLogin =
          globalThis.location.pathname === "/" ||
          globalThis.location.pathname.startsWith("/login") ||
          globalThis.location.pathname.startsWith("/auth");
        if (!isAlreadyOnLogin) {
          navigate("/", { replace: true });
        }
      } else if (error?.config?.meta?.silent !== true) {
        // Global UX feedback for unexpected errors. Callers can opt out by
        // passing { meta: { silent: true } } when they handle the error themselves.
        const serverMsg = error?.response?.data?.message;

        if (!error?.response) {
          notify.error("Pas de connexion au serveur. Vérifiez votre réseau.");
        } else if (status >= 500) {
          notify.error(serverMsg || "Erreur serveur. Réessayez dans un instant.");
        } else if (status === 403) {
          notify.warning(serverMsg || "Accès refusé.");
        } else if (status === 422) {
          notify.warning(serverMsg || "Données invalides ou insuffisantes.");
        }
        // 400/404/409 etc. are left to the caller for context-specific handling.
      }
      return Promise.reject(error);
    }
  );

  return api;
}

export const defaultApi = createApiClient();

import type { AxiosResponse } from "axios";
import { createApiClient } from "@/utils/helpers/httpClient";

import { config } from "@/config/env";
import type {
  LoginRequest,
  LoginResponse,
  ResetPasswordRequest,
  SignupRequest,
  AuthUser,
} from "@/models/auth";

const api = createApiClient(`${config.URL_ACCOUNT}/auth`);

/**
 * Authenticate user. JWT is set as HttpOnly cookie by the server.
 * Body returns only userId, role, email, expiresIn — NO token.
 */
export async function login({
  username,
  password,
}: LoginRequest): Promise<LoginResponse> {
  const params = new URLSearchParams();
  params.append("username", username);
  params.append("password", password);
  const response: AxiosResponse<LoginResponse> = await api.post(
    `/login`,
    params
  );

  // JWT is now in HttpOnly cookie — no localStorage
  return response.data;
}

export async function signup(payload: SignupRequest): Promise<unknown> {
  const response = await api.post("/signup", payload);
  return response.data;
}

export async function forgotPassword(emailAddress: string): Promise<unknown> {
  const url = `/forgot-password?emailAddress=${encodeURIComponent(
    emailAddress
  )}`;
  const response = await api.post(url);
  return response.data;
}

export async function resetPassword({
  confirmationKey,
  newPassword,
}: ResetPasswordRequest): Promise<unknown> {
  const response = await api.post(`/reset-password`, {
    confirmationKey,
    newPassword,
  });
  return response.data;
}

export async function getProfile(): Promise<AuthUser> {
  const response = await api.get("/profile");
  return response.data;
}

/**
 * Refresh JWT cookie silently. Server validates existing cookie
 * and returns a new one.
 */
export async function refreshToken(): Promise<LoginResponse> {
  const response: AxiosResponse<LoginResponse> = await api.get("/refresh");
  return response.data;
}

/**
 * Logout — server invalidates the HttpOnly cookie (Max-Age=0).
 */
export async function logout(): Promise<void> {
  await api.post("/logout");
}

import { useState, useMemo, useEffect, useCallback, useRef, createContext } from "react";
import { flushSync } from "react-dom";
import type { ReactNode } from "react";
import type { AuthUser, AuthContextValue, UserRole } from "@/models/auth";
import { refreshToken as refreshTokenApi, logout as logoutApi } from "@/services/auth/AuthService";

export const AuthContext = createContext<AuthContextValue | undefined>(undefined);

interface AuthProviderProps {
  children: ReactNode;
}

/** Silent refresh interval: 100 minutes (JWT lasts 120 min) */
const REFRESH_INTERVAL_MS = 100 * 60 * 1000;

const AuthProvider = ({ children }: AuthProviderProps) => {
  const [user, setUser] = useState<AuthUser | null>(() => {
    const storedUser = sessionStorage.getItem("d2f_user");
    if (storedUser) {
      try {
        return JSON.parse(storedUser) as AuthUser;
      } catch {
        sessionStorage.removeItem("d2f_user");
      }
    }
    return null;
  });

  const refreshTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const stopSilentRefresh = useCallback(() => {
    if (refreshTimerRef.current) {
      clearInterval(refreshTimerRef.current);
      refreshTimerRef.current = null;
    }
  }, []);

  const startSilentRefresh = useCallback(() => {
    if (refreshTimerRef.current) {
      clearInterval(refreshTimerRef.current);
    }
    refreshTimerRef.current = setInterval(() => {
      refreshTokenApi()
        .then((data) => {
          const updatedUser: AuthUser = {
            userId: data.userId,
            username: data.username,
            role: data.role,
            email: data.email,
            expiresIn: data.expiresIn,
          };
          setUser(updatedUser);
          try {
            sessionStorage.setItem("d2f_user", JSON.stringify(updatedUser));
          } catch {
            /* ignore */
          }
        })
        .catch(() => {
          stopSilentRefresh();
          setUser(null);
          sessionStorage.removeItem("d2f_user");
          try {
            globalThis.dispatchEvent(new Event("auth:loggedOut"));
          } catch {
            /* ignore */
          }
        });
    }, REFRESH_INTERVAL_MS);
  }, [stopSilentRefresh]);

  useEffect(() => {
    if (user) {
      startSilentRefresh();
    }
    return () => stopSilentRefresh();
  }, [user, startSilentRefresh, stopSilentRefresh]);

  useEffect(() => {
    if (user) {
      refreshTokenApi()
        .then((data) => {
          const updatedUser: AuthUser = {
            userId: data.userId,
            username: data.username,
            role: data.role as UserRole,
            email: data.email,
            expiresIn: data.expiresIn,
          };
          setUser(updatedUser);
          try {
            sessionStorage.setItem("d2f_user", JSON.stringify(updatedUser));
          } catch {
            /* ignore */
          }
        })
        .catch(() => {
          setUser(null);
          sessionStorage.removeItem("d2f_user");
        });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const onAuthLoggedOut = () => {
      stopSilentRefresh();
      sessionStorage.removeItem("d2f_user");
      try {
        flushSync(() => setUser(null));
      } catch {
        setUser(null);
      }
    };
    globalThis.addEventListener("auth:loggedOut", onAuthLoggedOut);
    return () => globalThis.removeEventListener("auth:loggedOut", onAuthLoggedOut);
  }, [stopSilentRefresh]);

  const login = useCallback((userData: AuthUser) => {
    try {
      sessionStorage.setItem("d2f_user", JSON.stringify(userData));
    } catch {
      /* ignore */
    }
    try {
      flushSync(() => setUser(userData));
    } catch {
      setUser(userData);
    }
    startSilentRefresh();
  }, [startSilentRefresh]);

  const logout = useCallback(() => {
    stopSilentRefresh();
    logoutApi()
      .catch(() => { /* ignore */ })
      .finally(() => {
        sessionStorage.removeItem("d2f_user");
        try {
          flushSync(() => setUser(null));
        } catch {
          setUser(null);
        }
      });
  }, [stopSilentRefresh]);

  const authValue = useMemo<AuthContextValue>(
    () => ({ user, login, logout }),
    [user, login, logout]
  );

  return <AuthContext.Provider value={authValue}>{children}</AuthContext.Provider>;
};

export default AuthProvider;

/**
 * storage.js — Abstraction du localStorage — D2F Webapp
 * =============================================================================
 * Centralise toutes les clés localStorage pour éviter les fautes de frappe
 * dispersées dans le code et faciliter la maintenance.
 *
 * Conformité DSI §1.3 : Modularité et Réutilisabilité
 * Conformité DSI §1.4 : Organisation Structurée du Code (src/utils/)
 * =============================================================================
 */

// ── Clés centralisées ─────────────────────────────────────────────────────────
const KEYS = {
  AUTH_TOKEN: "authToken",
  USER_PROFILE: "userProfile",
  ACTIVE_ROLE: "activeRole",
  PREFERRED_LANG: "preferredLang",
};

// ── Token JWT — DEPRECATED ────────────────────────────────────────────────────
// JWT est maintenant stocké en HttpOnly cookie (withCredentials: true).
// Ces fonctions ne font rien et sont conservées uniquement pour éviter de
// casser d'éventuels imports existants. À supprimer lors du prochain refactor.

/** @deprecated JWT est en HttpOnly cookie. Retourne toujours null. */
export const getToken = (): null => null;

/** @deprecated JWT est positionné par le backend via Set-Cookie. */
export const setToken = (_token: string): void => { /* no-op */ };

/** @deprecated Utilisez AuthService.logout() pour invalider la session. */
export const removeToken = (): void => { /* no-op */ };

/** @deprecated JWT est en HttpOnly cookie, non accessible depuis JS. */
export const hasToken = (): false => false;

// ── Profil utilisateur ────────────────────────────────────────────────────────

/**
 * Récupère le profil utilisateur désérialisé.
 * @returns {object|null}
 */
export const getProfile = () => {
  const raw = localStorage.getItem(KEYS.USER_PROFILE);
  try {
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
};

/**
 * Stocke le profil utilisateur sérialisé.
 * @param {object} profile
 */
export const setProfile = (profile: Record<string, unknown>): void =>
  localStorage.setItem(KEYS.USER_PROFILE, JSON.stringify(profile));

/**
 * Supprime le profil utilisateur.
 */
export const removeProfile = () => localStorage.removeItem(KEYS.USER_PROFILE);

// ── Rôle actif ────────────────────────────────────────────────────────────────

/**
 * Récupère le rôle actif de l'utilisateur.
 * @returns {string|null}
 */
export const getActiveRole = () => localStorage.getItem(KEYS.ACTIVE_ROLE);

/**
 * Stocke le rôle actif.
 * @param {string} role
 */
export const setActiveRole = (role: string): void =>
  localStorage.setItem(KEYS.ACTIVE_ROLE, role);

/**
 * Supprime le rôle actif.
 */
export const removeActiveRole = () => localStorage.removeItem(KEYS.ACTIVE_ROLE);

// ── Langue préférée ───────────────────────────────────────────────────────────

/**
 * Récupère la langue préférée de l'utilisateur.
 * @returns {string} code langue (ex: "fr", "en"), "fr" par défaut
 */
export const getPreferredLang = () =>
  localStorage.getItem(KEYS.PREFERRED_LANG) ?? "fr";

/**
 * Stocke la langue préférée.
 * @param {string} lang
 */
export const setPreferredLang = (lang: string): void =>
  localStorage.setItem(KEYS.PREFERRED_LANG, lang);

// ── Utilitaires globaux ───────────────────────────────────────────────────────

/**
 * Supprime toutes les données de session (logout complet).
 */
export const clearSession = () => {
  localStorage.removeItem(KEYS.USER_PROFILE);
  localStorage.removeItem(KEYS.ACTIVE_ROLE);
};

/**
 * Objet regroupant toutes les méthodes (API objet alternative).
 * Utile pour les injections de dépendances ou les tests.
 */
export const storage = {
  getToken,
  setToken,
  removeToken,
  hasToken,
  getProfile,
  setProfile,
  removeProfile,
  getActiveRole,
  setActiveRole,
  removeActiveRole,
  getPreferredLang,
  setPreferredLang,
  clearSession,
};

export default storage;

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import { config } from "@/config/env";
import type { Id, ApiListOrPage } from "@/models/common";
import type { BesoinFormation } from "@/models/besoin";

const API_URL = `${config.Besoin_URL}/besoins-formation`;

interface ModifyBesoinPayload {
  besoinFormation: Partial<BesoinFormation>;
  commentaire: string;
}

export interface BesoinNotification {
  id?: Id;
  message?: string;
  read?: boolean;
  createdAt?: string;
  [key: string]: unknown;
}

const BesoinFormationService = {
  async getAllBesoinFormations(): Promise<BesoinFormation[]> {
    const response = await axios.get<ApiListOrPage<BesoinFormation>>(`${API_URL}`);
    return (response.data as { content?: BesoinFormation[] }).content ?? (response.data as BesoinFormation[]) ?? [];
  },

  async getBesoinFormation(id: Id): Promise<BesoinFormation> {
    const response = await axios.get<BesoinFormation>(`${API_URL}/${id}`);
    return response.data;
  },

  async addBesoinFormation(
    besoin: Partial<BesoinFormation>
  ): Promise<BesoinFormation> {
    const response = await axios.post<BesoinFormation>(`${API_URL}`, besoin);
    return response.data;
  },

  async removeBesoinFormation(id: Id): Promise<unknown> {
    const response = await axios.delete(`${API_URL}/${id}`);
    return response.data;
  },

  async modifyBesoinFormation(
    besoinFormation: Partial<BesoinFormation>,
    commentaire: string
  ): Promise<BesoinFormation> {
    const payload: ModifyBesoinPayload = {
      besoinFormation,
      commentaire,
    };
    const response = await axios.put<BesoinFormation>(`${API_URL}`, payload);
    return response.data;
  },

  async getApprovedBesoinFormations(): Promise<BesoinFormation[]> {
    const response = await axios.get<ApiListOrPage<BesoinFormation>>(`${API_URL}/approved`);
    return (response.data as { content?: BesoinFormation[] }).content ?? (response.data as BesoinFormation[]) ?? [];
  },

  async approveBesoin(id: Id): Promise<BesoinFormation> {
    const response = await axios.put<BesoinFormation>(`${API_URL}/${id}/approve`);
    return response.data;
  },

  async getUserNotifications(username: string): Promise<BesoinNotification[]> {
    const response = await axios.get<ApiListOrPage<BesoinNotification>>(`${API_URL}/notifications/${username}`);
    return (response.data as { content?: BesoinNotification[] }).content ?? (response.data as BesoinNotification[]) ?? [];
  },

  async getBesoinsByUp(up: string): Promise<BesoinFormation[]> {
    const response = await axios.get<ApiListOrPage<BesoinFormation>>(`${API_URL}/by-up/${up}`);
    return (response.data as { content?: BesoinFormation[] }).content ?? (response.data as BesoinFormation[]) ?? [];
  },

  async getBesoinsByDepartement(departement: string): Promise<BesoinFormation[]> {
    const response = await axios.get<ApiListOrPage<BesoinFormation>>(`${API_URL}/by-departement/${departement}`);
    return (response.data as { content?: BesoinFormation[] }).content ?? (response.data as BesoinFormation[]) ?? [];
  },

  async getBesoinsByPriorite(): Promise<BesoinFormation[]> {
    const response = await axios.get<ApiListOrPage<BesoinFormation>>(`${API_URL}/by-priorite`);
    return (response.data as { content?: BesoinFormation[] }).content ?? (response.data as BesoinFormation[]) ?? [];
  },

  async getBesoinsByPrioriteLevel(priorite: string): Promise<BesoinFormation[]> {
    const response = await axios.get<ApiListOrPage<BesoinFormation>>(`${API_URL}/by-priorite/${priorite}`);
    return (response.data as { content?: BesoinFormation[] }).content ?? (response.data as BesoinFormation[]) ?? [];
  },
};

export default BesoinFormationService;

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import { config } from "@/config/env";

const BASE = `${config.Besoin_URL}/besoins-formation`;

export interface BesoinCompetenceLink {
  id?: number;
  besoinId?: number;
  domaineId?: number | null;
  competenceId?: number | null;
  competenceNom?: string;
  savoirId?: number | null;
  savoirNom?: string;
  sousCompetenceId?: number | null;
}

const BesoinCompetenceService = {
  async getByBesoin(besoinId: number): Promise<BesoinCompetenceLink[]> {
    const r = await axios.get<BesoinCompetenceLink[]>(`${BASE}/${besoinId}/competences`);
    return r.data;
  },

  async replaceAll(besoinId: number, links: BesoinCompetenceLink[]): Promise<BesoinCompetenceLink[]> {
    const r = await axios.put<BesoinCompetenceLink[]>(`${BASE}/${besoinId}/competences`, links);
    return r.data;
  },
};

export default BesoinCompetenceService;

import { defaultApi as axios } from "@/utils/helpers/httpClient";
import type { AxiosResponse } from "axios";
import { config } from "@/config/env";
import type { ApiListOrPage, Id } from "@/models/common";
import type {
  Competence,
  Domaine,
  Savoir,
  SousCompetence,
} from "@/models/competence";

const BASE = `${config.COMPETENCE_URL}/competence`;



const toList = <T>(payload: ApiListOrPage<T>): T[] =>
  Array.isArray(payload) ? payload : payload.content ?? [];

type TreeNode = Record<string, unknown>;
type NiveauDefinition = Record<string, unknown>;
type EnseignantCompetence = Record<string, unknown>;
type AssignRequest = Record<string, unknown>;
type PrerequisiteRequest = Record<string, unknown>;

const DomaineAPI = {
  getAll: async (upId?: number | null, departementId?: number | null): Promise<Domaine[]> => {
    const params = new URLSearchParams();
    if (upId)          params.set("upId",          String(upId));
    if (departementId) params.set("departementId", String(departementId));
    const res = await axios.get<ApiListOrPage<Domaine>>(`${BASE}/domaines?${params}`);
    return toList(res.data);
  },

  getActifs: async (upId?: number | null, departementId?: number | null): Promise<Domaine[]> => {
    const params = new URLSearchParams();
    if (upId)          params.set("upId",          String(upId));
    if (departementId) params.set("departementId", String(departementId));
    const query = params.toString() ? `?${params}` : "";
    const res = await axios.get<Domaine[]>(`${BASE}/domaines/actifs${query}`);
    return res.data;
  },

  getById: async (id: Id): Promise<Domaine> => {
    const res = await axios.get<Domaine>(`${BASE}/domaines/${id}`);
    return res.data;
  },

  create: async (domaine: Partial<Domaine>): Promise<Domaine> => {
    const res = await axios.post<Domaine>(`${BASE}/domaines`, domaine);
    return res.data;
  },

  update: async (id: Id, domaine: Partial<Domaine>): Promise<Domaine> => {
    const res = await axios.put<Domaine>(`${BASE}/domaines/${id}`, domaine);
    return res.data;
  },

  delete: (id: Id): Promise<AxiosResponse<unknown>> =>
    axios.delete(`${BASE}/domaines/${id}`),

  toggleActif: async (id: Id): Promise<Domaine> => {
    const res = await axios.patch<Domaine>(
      `${BASE}/domaines/${id}/toggle-actif`,
      {},

    );
    return res.data;
  },
};

const CompetenceAPI = {
  getAll: async (): Promise<Competence[]> => {
    const res = await axios.get<ApiListOrPage<Competence>>(
      `${BASE}/competences`,

    );
    return toList(res.data);
  },

  getByDomaine: async (domaineId: Id): Promise<Competence[]> => {
    const res = await axios.get<Competence[]>(`${BASE}/competences/domaine/${domaineId}`);
    return res.data;
  },

  getById: async (id: Id): Promise<Competence> => {
    const res = await axios.get<Competence>(`${BASE}/competences/${id}`);
    return res.data;
  },

  create: async (
    domaineId: Id,
    competence: Partial<Competence>
  ): Promise<Competence> => {
    const res = await axios.post<Competence>(
      `${BASE}/competences/domaine/${domaineId}`,
      competence,

    );
    return res.data;
  },

  update: async (id: Id, competence: Partial<Competence>): Promise<Competence> => {
    const res = await axios.put<Competence>(`${BASE}/competences/${id}`, competence);
    return res.data;
  },

  delete: (id: Id): Promise<AxiosResponse<unknown>> =>
    axios.delete(`${BASE}/competences/${id}`),
};

const SousCompetenceAPI = {
  getAll: async (): Promise<SousCompetence[]> => {
    const res = await axios.get<ApiListOrPage<SousCompetence>>(
      `${BASE}/sous-competences`,

    );
    return toList(res.data);
  },

  getByCompetence: async (competenceId: Id): Promise<SousCompetence[]> => {
    const res = await axios.get<SousCompetence[]>(
      `${BASE}/sous-competences/competence/${competenceId}`,

    );
    return res.data;
  },

  getById: async (id: Id): Promise<SousCompetence> => {
    const res = await axios.get<SousCompetence>(`${BASE}/sous-competences/${id}`);
    return res.data;
  },

  create: async (
    competenceId: Id,
    sousCompetence: Partial<SousCompetence>
  ): Promise<SousCompetence> => {
    const res = await axios.post<SousCompetence>(
      `${BASE}/sous-competences/competence/${competenceId}`,
      sousCompetence,

    );
    return res.data;
  },

  createEnfant: async (
    parentId: Id,
    sousCompetence: Partial<SousCompetence>
  ): Promise<SousCompetence> => {
    const res = await axios.post<SousCompetence>(
      `${BASE}/sous-competences/${parentId}/enfants`,
      sousCompetence,

    );
    return res.data;
  },

